class Solution:
    def checkSubarraySum(self, nums: List[int], k: int) -> bool:
        n = len(nums)
        prefix_sum = {0: -1}
        total_sum = 0
        for i in range(n):
            total_sum += nums[i]
            if k != 0:
                total_sum %= k
            if total_sum in prefix_sum:
                if i - prefix_sum[total_sum] > 1:
                    return True
            else:
                prefix_sum[total_sum] = i
        return False
```

